1	/**
2	 * DashboardPage — KPI cards and charts.
3	 */
4	
5	import dashboardService from '../services/DashboardService.js';
6	import authService from '../services/AuthService.js';
7	import Chart from '../components/Chart.js';
8	
9	export class DashboardPage {
10	  constructor(appShell) {
11	    this.appShell = appShell;
12	  }
13	
14	  async render() {
15	    this.appShell.setPageTitle('Dashboard');
16	    const container = this.appShell.getContentContainer();
17	
18	    container.innerHTML = '<p>Loading dashboard...</p>';
19	
20	    try {
21	      const user = authService.getCurrentUser();
22	      const kpis = await dashboardService.getKPIs(user?.id);
23	
24	      container.innerHTML = `
25	        <div class="kpi-grid" id="kpi-grid"></div>
26	        <div class="charts-grid">
27	          <div id="chart-registrations"></div>
28	          <div id="chart-approval-rate"></div>
29	        </div>
30	      `;
31	
32	      // KPI Cards
33	      const kpiData = [
34	        { label: 'Total Registrations', value: kpis.totalRegistrations },
35	        { label: 'Pending', value: kpis.pendingRegistrations },
36	        { label: 'Approved', value: kpis.approvedRegistrations },
37	        { label: 'Rejected', value: kpis.rejectedRegistrations },
38	        { label: 'Avg Quiz Score', value: kpis.averageQuizScore + '%' },
39	        { label: 'Open Reports', value: kpis.openReports },
40	        { label: 'Avg Resolution (days)', value: kpis.avgResolutionDays },
41	        { label: 'Avg Fill Rate', value: kpis.averageFillRate + '%' },
42	      ];
43	
44	      const kpiGrid = container.querySelector('#kpi-grid');
45	      kpiGrid.innerHTML = kpiData.map(k => `
46	        <div class="kpi-card">
47	          <div class="kpi-label">${k.label}</div>
48	          <div class="kpi-value">${k.value}</div>
49	        </div>
50	      `).join('');
51	
52	      // Charts
53	      Chart.bar(container.querySelector('#chart-registrations'), {
54	        title: 'Registrations by Status',
55	        data: [
56	          { label: 'Approved', value: kpis.approvedRegistrations, color: 'var(--color-success)' },
57	          { label: 'Rejected', value: kpis.rejectedRegistrations, color: 'var(--color-danger)' },
58	          { label: 'Pending', value: kpis.pendingRegistrations, color: 'var(--color-warning)' },
59	        ],
60	      });
61	
62	      Chart.percentage(container.querySelector('#chart-approval-rate'), {
63	        title: 'Approval Rate',
64	        value: kpis.approvalRate,
65	        subtitle: 'of all registrations',
66	      });
67	    } catch (err) {
68	      container.innerHTML = `<p class="form-error">Failed to load dashboard: ${err.message}</p>`;
69	    }
70	  }
71	}
72	
73	export default DashboardPage;
74	
