1	/**
2	 * excelParser — lightweight .xlsx parser using JSZip-style approach.
3	 * Parses XLSX (Open XML) files by unzipping and reading the XML content.
4	 * No external dependencies — uses browser APIs only.
5	 *
6	 * XLSX structure:
7	 *   xl/sharedStrings.xml — string table
8	 *   xl/worksheets/sheet1.xml — cell data
9	 *
10	 * Supports: .xlsx files (Office Open XML)
11	 * For .xls (legacy binary), converts to a user-friendly error.
12	 */
13	
14	/**
15	 * Parse an Excel file (.xlsx) into an array of row objects.
16	 * The first row is treated as headers.
17	 *
18	 * @param {ArrayBuffer} buffer — file contents as ArrayBuffer
19	 * @param {string} filename — original filename for format detection
20	 * @returns {Array<Object>} rows as key-value objects using header names
21	 */
22	export async function parseExcelFile(buffer, filename) {
23	  const lower = (filename || '').toLowerCase();
24	
25	  if (lower.endsWith('.xls') && !lower.endsWith('.xlsx')) {
26	    throw new Error('Legacy .xls format is not supported. Please save the file as .xlsx and try again.');
27	  }
28	
29	  if (!lower.endsWith('.xlsx')) {
30	    throw new Error('Unsupported file format. Please use .xlsx files.');
31	  }
32	
33	  try {
34	    const entries = await unzip(buffer);
35	    const sharedStrings = parseSharedStrings(entries['xl/sharedStrings.xml']);
36	    const sheetXml = entries['xl/worksheets/sheet1.xml'];
37	    if (!sheetXml) {
38	      throw new Error('No worksheet found in Excel file.');
39	    }
40	    const rows = parseSheet(sheetXml, sharedStrings);
41	    if (rows.length < 2) {
42	      throw new Error('Excel file must have a header row and at least one data row.');
43	    }
44	
45	    // First row = headers
46	    const headers = rows[0].map(h => String(h || '').trim());
47	    const data = [];
48	    for (let i = 1; i < rows.length; i++) {
49	      const row = rows[i];
50	      // Skip completely empty rows
51	      if (row.every(cell => cell === '' || cell === null || cell === undefined)) continue;
52	      const obj = {};
53	      for (let j = 0; j < headers.length; j++) {
54	        if (headers[j]) {
55	          obj[headers[j]] = row[j] !== undefined ? row[j] : '';
56	        }
57	      }
58	      data.push(obj);
59	    }
60	    return data;
61	  } catch (err) {
62	    if (err.message.includes('not supported') || err.message.includes('Unsupported') || err.message.includes('header row')) {
63	      throw err;
64	    }
65	    throw new Error(`Failed to parse Excel file: ${err.message}`);
66	  }
67	}
68	
69	/**
70	 * Minimal ZIP reader — extracts text entries from a ZIP (XLSX) ArrayBuffer.
71	 */
72	async function unzip(buffer) {
73	  const view = new DataView(buffer);
74	  const entries = {};
75	
76	  let offset = 0;
77	  while (offset < buffer.byteLength - 4) {
78	    const sig = view.getUint32(offset, true);
79	    if (sig !== 0x04034b50) break; // Local file header signature
80	
81	    const compressedSize = view.getUint32(offset + 18, true);
82	    const uncompressedSize = view.getUint32(offset + 22, true);
83	    const nameLen = view.getUint16(offset + 26, true);
84	    const extraLen = view.getUint16(offset + 28, true);
85	    const compressionMethod = view.getUint16(offset + 8, true);
86	
87	    const nameBytes = new Uint8Array(buffer, offset + 30, nameLen);
88	    const name = new TextDecoder().decode(nameBytes);
89	
90	    const dataStart = offset + 30 + nameLen + extraLen;
91	
92	    if (name.endsWith('.xml') || name.endsWith('.rels')) {
93	      const compressedData = new Uint8Array(buffer, dataStart, compressedSize);
94	
95	      if (compressionMethod === 0) {
96	        // Stored (no compression)
97	        entries[name] = new TextDecoder().decode(compressedData);
98	      } else if (compressionMethod === 8) {
99	        // Deflate
100	        try {
101	          const ds = new DecompressionStream('deflate-raw');
102	          const writer = ds.writable.getWriter();
103	          const reader = ds.readable.getReader();
104	
105	          writer.write(compressedData);
106	          writer.close();
107	
108	          const chunks = [];
109	          while (true) {
110	            const { done, value } = await reader.read();
111	            if (done) break;
112	            chunks.push(value);
113	          }
114	          const totalLen = chunks.reduce((s, c) => s + c.length, 0);
115	          const result = new Uint8Array(totalLen);
116	          let pos = 0;
117	          for (const chunk of chunks) {
118	            result.set(chunk, pos);
119	            pos += chunk.length;
120	          }
121	          entries[name] = new TextDecoder().decode(result);
122	        } catch {
123	          // Skip entries that fail to decompress
124	        }
125	      }
126	    }
127	
128	    offset = dataStart + compressedSize;
129	  }
130	
131	  return entries;
132	}
133	
134	/**
135	 * Parse xl/sharedStrings.xml into an array of strings.
136	 */
137	function parseSharedStrings(xml) {
138	  if (!xml) return [];
139	  const strings = [];
140	  // Match <si>...<t>...</t>...</si> patterns
141	  const siRegex = /<si>([\s\S]*?)<\/si>/g;
142	  let match;
143	  while ((match = siRegex.exec(xml)) !== null) {
144	    const siContent = match[1];
145	    // Extract all <t> values within this <si> and concatenate (handles rich text <r><t>...</t></r>)
146	    const tRegex = /<t[^>]*>([\s\S]*?)<\/t>/g;
147	    let tMatch;
148	    let value = '';
149	    while ((tMatch = tRegex.exec(siContent)) !== null) {
150	      value += tMatch[1];
151	    }
152	    strings.push(decodeXmlEntities(value));
153	  }
154	  return strings;
155	}
156	
157	/**
158	 * Parse xl/worksheets/sheet1.xml into a 2D array of cell values.
159	 */
160	function parseSheet(xml, sharedStrings) {
161	  const rows = [];
162	  const rowRegex = /<row[^>]*>([\s\S]*?)<\/row>/g;
163	  let rowMatch;
164	
165	  while ((rowMatch = rowRegex.exec(xml)) !== null) {
166	    const rowContent = rowMatch[1];
167	    const cells = [];
168	    const cellRegex = /<c\s([^>]*)(?:\/>|>([\s\S]*?)<\/c>)/g;
169	    let cellMatch;
170	
171	    while ((cellMatch = cellRegex.exec(rowContent)) !== null) {
172	      const attrs = cellMatch[1];
173	      const cellContent = cellMatch[2] || '';
174	
175	      // Get cell reference to determine column index
176	      const refMatch = attrs.match(/r="([A-Z]+)\d+"/);
177	      const colIndex = refMatch ? colLetterToIndex(refMatch[1]) : cells.length;
178	
179	      // Pad with empty cells if needed
180	      while (cells.length < colIndex) cells.push('');
181	
182	      // Get type attribute
183	      const typeMatch = attrs.match(/t="([^"]*)"/);
184	      const cellType = typeMatch ? typeMatch[1] : '';
185	
186	      // Extract value
187	      const vMatch = cellContent.match(/<v>([\s\S]*?)<\/v>/);
188	      const rawValue = vMatch ? vMatch[1] : '';
189	
190	      let value;
191	      if (cellType === 's') {
192	        // Shared string reference
193	        const idx = parseInt(rawValue, 10);
194	        value = sharedStrings[idx] || '';
195	      } else if (cellType === 'inlineStr') {
196	        const tMatch = cellContent.match(/<t[^>]*>([\s\S]*?)<\/t>/);
197	        value = tMatch ? decodeXmlEntities(tMatch[1]) : '';
198	      } else {
199	        value = decodeXmlEntities(rawValue);
200	      }
201	
202	      cells.push(value);
203	    }
204	
205	    rows.push(cells);
206	  }
207	
208	  return rows;
209	}
210	
211	/**
212	 * Convert column letter(s) to 0-based index. A=0, B=1, ..., Z=25, AA=26...
213	 */
214	function colLetterToIndex(letters) {
215	  let index = 0;
216	  for (let i = 0; i < letters.length; i++) {
217	    index = index * 26 + (letters.charCodeAt(i) - 64);
218	  }
219	  return index - 1;
220	}
221	
222	/**
223	 * Decode basic XML entities.
224	 */
225	function decodeXmlEntities(str) {
226	  return str
227	    .replace(/&amp;/g, '&')
228	    .replace(/&lt;/g, '<')
229	    .replace(/&gt;/g, '>')
230	    .replace(/&quot;/g, '"')
231	    .replace(/&apos;/g, "'");
232	}
