86	/**
87	 * Minimal ZIP reader — extracts text entries from a ZIP (XLSX) ArrayBuffer.
88	 */
89	async function unzip(buffer) {
90	  if (typeof DecompressionStream === 'undefined') {
91	    throw new Error('Excel import is only supported in modern Chromium browsers (Chrome, Edge). Your browser does not support DecompressionStream.');
92	  }
93	
94	  const view = new DataView(buffer);
95	  const entries = {};
96	
97	  let offset = 0;
98	  while (offset < buffer.byteLength - 4) {
99	    const sig = view.getUint32(offset, true);
100	    if (sig !== 0x04034b50) break; // Local file header signature
101	
102	    const compressedSize = view.getUint32(offset + 18, true);
103	    const uncompressedSize = view.getUint32(offset + 22, true);
104	    const nameLen = view.getUint16(offset + 26, true);
105	    const extraLen = view.getUint16(offset + 28, true);
106	    const compressionMethod = view.getUint16(offset + 8, true);
107	
108	    const nameBytes = new Uint8Array(buffer, offset + 30, nameLen);
109	    const name = new TextDecoder().decode(nameBytes);
110	
111	    const dataStart = offset + 30 + nameLen + extraLen;
112	
113	    if (name.endsWith('.xml') || name.endsWith('.rels')) {
114	      const compressedData = new Uint8Array(buffer, dataStart, compressedSize);
115	
116	      if (compressionMethod === 0) {
117	        // Stored (no compression)
118	        entries[name] = new TextDecoder().decode(compressedData);
119	      } else if (compressionMethod === 8) {
120	        // Deflate
121	        try {
122	          const ds = new DecompressionStream('deflate-raw');
123	          const writer = ds.writable.getWriter();
124	          const reader = ds.readable.getReader();
125	
126	          writer.write(compressedData);
127	          writer.close();
128	
129	          const chunks = [];
130	          while (true) {
131	            const { done, value } = await reader.read();
132	            if (done) break;
133	            chunks.push(value);
134	          }
135	          const totalLen = chunks.reduce((s, c) => s + c.length, 0);
136	          const result = new Uint8Array(totalLen);
137	          let pos = 0;
138	          for (const chunk of chunks) {
139	            result.set(chunk, pos);
140	            pos += chunk.length;
141	          }
142	          entries[name] = new TextDecoder().decode(result);
143	        } catch {
144	          // Skip entries that fail to decompress
145	        }
146	      }
147	    }
148	
149	    offset = dataStart + compressedSize;
150	  }
151	
152	  return entries;
153	}
