155	/**
156	 * Parse xl/sharedStrings.xml into an array of strings.
157	 */
158	function parseSharedStrings(xml) {
159	  if (!xml) return [];
160	  const strings = [];
161	  // Match <si>...<t>...</t>...</si> patterns
162	  const siRegex = /<si>([\s\S]*?)<\/si>/g;
163	  let match;
164	  while ((match = siRegex.exec(xml)) !== null) {
165	    const siContent = match[1];
166	    // Extract all <t> values within this <si> and concatenate (handles rich text <r><t>...</t></r>)
167	    const tRegex = /<t[^>]*>([\s\S]*?)<\/t>/g;
168	    let tMatch;
169	    let value = '';
170	    while ((tMatch = tRegex.exec(siContent)) !== null) {
171	      value += tMatch[1];
172	    }
173	    strings.push(decodeXmlEntities(value));
174	  }
175	  return strings;
176	}
177	
178	/**
179	 * Parse xl/worksheets/sheet1.xml into a 2D array of cell values.
180	 */
181	function parseSheet(xml, sharedStrings) {
182	  const rows = [];
183	  const rowRegex = /<row[^>]*>([\s\S]*?)<\/row>/g;
184	  let rowMatch;
185	
186	  while ((rowMatch = rowRegex.exec(xml)) !== null) {
187	    const rowContent = rowMatch[1];
188	    const cells = [];
189	    const cellRegex = /<c\s([^>]*)(?:\/>|>([\s\S]*?)<\/c>)/g;
190	    let cellMatch;
191	
192	    while ((cellMatch = cellRegex.exec(rowContent)) !== null) {
193	      const attrs = cellMatch[1];
194	      const cellContent = cellMatch[2] || '';
195	
196	      // Get cell reference to determine column index
197	      const refMatch = attrs.match(/r="([A-Z]+)\d+"/);
198	      const colIndex = refMatch ? colLetterToIndex(refMatch[1]) : cells.length;
199	
200	      // Pad with empty cells if needed
201	      while (cells.length < colIndex) cells.push('');
202	
203	      // Get type attribute
204	      const typeMatch = attrs.match(/t="([^"]*)"/);
205	      const cellType = typeMatch ? typeMatch[1] : '';
206	
207	      // Extract value
208	      const vMatch = cellContent.match(/<v>([\s\S]*?)<\/v>/);
209	      const rawValue = vMatch ? vMatch[1] : '';
210	
211	      let value;
212	      if (cellType === 's') {
213	        // Shared string reference
214	        const idx = parseInt(rawValue, 10);
215	        value = sharedStrings[idx] || '';
216	      } else if (cellType === 'inlineStr') {
217	        const tMatch = cellContent.match(/<t[^>]*>([\s\S]*?)<\/t>/);
218	        value = tMatch ? decodeXmlEntities(tMatch[1]) : '';
219	      } else {
220	        value = decodeXmlEntities(rawValue);
221	      }
222	
223	      cells.push(value);
224	    }
225	
226	    rows.push(cells);
227	  }
228	
229	  return rows;
230	}
231	
232	/**
233	 * Convert column letter(s) to 0-based index. A=0, B=1, ..., Z=25, AA=26...
234	 */
235	function colLetterToIndex(letters) {
236	  let index = 0;
237	  for (let i = 0; i < letters.length; i++) {
238	    index = index * 26 + (letters.charCodeAt(i) - 64);
239	  }
240	  return index - 1;
241	}
242	
243	/**
244	 * Decode basic XML entities.
245	 */
246	function decodeXmlEntities(str) {
247	  return str
248	    .replace(/&amp;/g, '&')
249	    .replace(/&lt;/g, '<')
250	    .replace(/&gt;/g, '>')
251	    .replace(/&quot;/g, '"')
252	    .replace(/&apos;/g, "'");
253	}
